# DK FPS.  Fredericia gamle - Pjedsted
#
let fp = path("d3.dk.fps");

with detail = 3,
     railway = :first :double :removed
{
    # point.dk.Fredericia-gamle  dk.FRT

    with link = "line.dk.FPS", layer = -2 {
        track(fp[:fre.ya + 0.99seg, :pje.yf - 2.5km]);
        line_label(:left:n, fp[:pje.yf - 2.5km] << 0.5md,
            (-0.3dt, 0dt), "FPS"
        );
        track(fp[:pje.yf - 2.5km, :pje.yf]);
    }
}

